// Extract bearer token + validate request shape.
// Expected body: { leads: [...], source, campaign_tag, lead_score, lead_type }
// Hard limit: 1000 leads per request to keep workflow snappy.
const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

if (!Array.isArray(body.leads)) {
  return { json: { ok: false, status: 400, error: 'body.leads must be an array' } };
}
if (body.leads.length === 0) {
  return { json: { ok: false, status: 400, error: 'body.leads is empty' } };
}
if (body.leads.length > 1000) {
  return { json: { ok: false, status: 400, error: 'Max 1000 leads per request. Split into batches.' } };
}

const source       = String(body.source || 'manual_import').trim().slice(0, 80);
const campaignTag  = String(body.campaign_tag || '').trim().slice(0, 120);
const leadType     = String(body.lead_type || 'existing_client').trim().slice(0, 60);
const leadScore    = Math.min(Math.max(parseInt(body.lead_score, 10) || 80, 0), 100);

return { json: { token, leads: body.leads, source, campaignTag, leadType, leadScore } };

// Validate admin role. Session validator returns either an array of
// rows or a single object depending on PostgREST shape settings.
const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required for bulk import' } };

const input = $('Extract Inputs').item.json;
return { json: {
  ok: true,
  leads: input.leads,
  source: input.source,
  campaignTag: input.campaignTag,
  leadType: input.leadType,
  leadScore: input.leadScore,
  importerEmail: row.email || ''
} };

// Build the leads rows for Supabase. Validate + sanitize each row.
// Dedupe within the batch by email (lowercased). Track skip reasons.
const v = $input.item.json;
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const safeStr = function (s, max) { return (s == null ? '' : String(s)).trim().slice(0, max || 200); };

const seen = new Set();
const rows = [];
const skipped = [];

for (let i = 0; i < v.leads.length; i++) {
  const lead = v.leads[i] || {};
  const email = safeStr(lead.email, 200).toLowerCase();
  const fullName = safeStr(lead.full_name || lead.name, 200);

  if (!email || !emailRe.test(email)) {
    skipped.push({ index: i, reason: 'invalid_email', value: email || '(blank)' });
    continue;
  }
  if (!fullName) {
    skipped.push({ index: i, reason: 'missing_full_name', email: email });
    continue;
  }
  if (seen.has(email)) {
    skipped.push({ index: i, reason: 'duplicate_in_batch', email: email });
    continue;
  }
  seen.add(email);

  // leads.company carries a UNIQUE constraint (the B2B one-lead-per-company dedup the
  // discovery / Lead Research pipeline depends on). Imported rows are PEOPLE - many share
  // or lack a company - so a shared/blank company collides (constraint 23505). Disambiguate
  // each row's company by its already-unique email; keep the real company name in notes.
  const realCompany = safeStr(lead.company, 160);
  const companyKey = (realCompany ? realCompany + ' | ' + email : 'Imported client | ' + email).slice(0, 200);

  const noteParts = ['Imported by ' + (v.importerEmail || 'admin') + ' on ' + new Date().toISOString().slice(0, 10)];
  if (realCompany) noteParts.push('Company: ' + realCompany);
  if (v.campaignTag) noteParts.push('Campaign: ' + v.campaignTag);
  if (lead.notes) noteParts.push('Notes: ' + safeStr(lead.notes, 1000));

  rows.push({
    full_name:         fullName,
    email:             email,
    phone:             safeStr(lead.phone, 40),
    company:           companyKey,
    job_title:         safeStr(lead.job_title, 120),
    industry:          safeStr(lead.industry, 80) || 'insurance',
    city:              safeStr(lead.city, 120),
    source:            v.source,
    lead_status:       'New Lead',
    product_type:      safeStr(lead.product_type, 80) || 'insurance',
    lead_type:         v.leadType,
    do_not_contact:    false,
    unsubscribed:      false,
    total_emails_sent: 0,
    lead_score:        v.leadScore,
    notes:             noteParts.join('\n').slice(0, 2000)
  });
}

return { json: { rowsToInsert: rows, skipped: skipped, requested: v.leads.length } };

// Build the final response. Supabase returns an array of inserted
// rows on success, or an error object on failure. Collapse n8n's
// array-split behavior with allOf() (see CLAUDE.md).
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items.filter(function (x) { return x && (x.id || x.email); });
  } catch (e) { return []; }
};

const built = $('Build + Validate Rows').item.json;
const inserted = allOf('Insert Leads');
const supabaseResp = $('Insert Leads').first().json;
const hadDbError = supabaseResp && supabaseResp.code && supabaseResp.message && !inserted.length;

if (hadDbError) {
  return { json: {
    ok: false,
    status: 500,
    error: 'Supabase rejected the insert: ' + supabaseResp.message,
    db_code: supabaseResp.code || null,
    requested: built.requested,
    valid_rows: built.rowsToInsert.length,
    skipped: built.skipped
  } };
}

return { json: {
  ok: true,
  requested: built.requested,
  imported: inserted.length,
  skipped: built.skipped.length,
  skip_details: built.skipped,
  sample_ids: inserted.slice(0, 3).map(function (r) { return r.id; })
} };
